#include <stdio.h>
#include <string.h>

int countEvenOnes(char *N) {
    int count = 0;
    for (int i = 0; i <= atoi(N); i++) {
        int ones = 0;
        int temp = i;
        while (temp) {
            ones += temp & 1;
            temp >>= 1;
        }
        if (ones % 2 == 0) count++;
    }
    return count;
}

int main() {
    char N[1000001];
    int M;
    scanf("%s %d", N, &M);
    for (int i = 0; i < M; i++) {
        int L, R;
        scanf("%d %d", &L, &R);
        for (int j = L - 1; j < R; j++) {
            if (N[j] == '0') N[j] = '1';
            else N[j] = '0';
        }
        printf("%d\n", countEvenOnes(N));
    }
    return 0;
}

