import java.util.Scanner;

public class Main {
    public static int countEvenOnes(String N) {
        int count = 0;
        for (int i = 0; i <= Integer.parseInt(N); i++) {
            int ones = 0;
            int temp = i;
            while (temp > 0) {
                ones += temp & 1;
                temp >>= 1;
            }
            if (ones % 2 == 0) count++;
        }
        return count;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String N = sc.next();
        int M = sc.nextInt();
        for (int i = 0; i < M; i++) {
            int L = sc.nextInt();
            int R = sc.nextInt();
            StringBuilder sb = new StringBuilder(N);
            for (int j = L - 1; j < R; j++) {
                if (sb.charAt(j) == '0') sb.setCharAt(j, '1');
                else sb.setCharAt(j, '0');
            }
            N = sb.toString();
            System.out.println(countEvenOnes(N));
        }
    }
}

